const ASSETS = {"/index.html":{"body":"","type":"text/html; charset=utf-8"},"/styles.css":{"body":"","type":"text/css; charset=utf-8"},"/app.js":{"body":"","type":"text/javascript; charset=utf-8"},"/manifest.json":{"body":"","type":"application/json; charset=utf-8"},"/service-worker.js":{"body":"","type":"text/javascript; charset=utf-8"},"/public/app-icon-96.png":{"body":"","type":"image/png"},"/public/app-icon-192.png":{"body":"","type":"image/png"},"/public/app-icon-512.png":{"body":"","type":"image/png"},"/public/mobilepay-qr.png":{"body":"","type":"image/png"},"/public/login-background.jpg":{"body":"","type":"image/jpeg"},"/":{"body":"","type":"text/html; charset=utf-8"}};

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = url.pathname.endsWith("/") && url.pathname !== "/" ? url.pathname.slice(0, -1) : url.pathname;
    const asset = ASSETS[path] || ASSETS[path + ".html"] || ASSETS["/index.html"];
    const noStore = ["/", "/index.html", "/app.js", "/styles.css", "/manifest.json", "/service-worker.js"].includes(path);
    const headers = new Headers({
      "content-type": asset.type,
      "cache-control": noStore ? "no-store" : "public, max-age=3600",
    });
    const body = Uint8Array.from(atob(asset.body), (char) => char.charCodeAt(0));
    return new Response(body, { headers });
  },
};
